import { useState, useEffect } from "react";
import { useNavigate, useSearchParams } from "react-router-dom";
import api from "../services/api";
import QuestionList from "../components/QuestionList";

export default function Home() {
  const [mounted, setMounted]           = useState(false);
  const [scanY, setScanY]               = useState(0);
  const [activeTag, setActiveTag]       = useState(null);
  const [activeFilter, setActiveFilter] = useState("Latest");
  const [tags, setTags]                 = useState([]);   // derived from real questions
  const [tagsLoading, setTagsLoading]   = useState(true);
  const [totalQuestions, setTotalQuestions] = useState(null);
  const [searchParams]                  = useSearchParams();
  const navigate                        = useNavigate();

  const searchQuery = searchParams.get("search") || "";

  useEffect(() => {
    setTimeout(() => setMounted(true), 80);
    const iv = setInterval(() => setScanY(v => (v + 0.5) % 100), 22);
    return () => clearInterval(iv);
  }, []);

  // ── Derive tags from questions ──────────────────────────────────────────
  // Instead of relying on a separate /tags endpoint (which may not exist),
  // we fetch all questions and extract unique tags + how many questions use each.
  useEffect(() => {
    const fetchTagsFromQuestions = async () => {
      setTagsLoading(true);
      try {
        // Try a dedicated /tags endpoint first
        try {
          const res = await api.get("/tags");
          const raw = res.data?.tags ?? res.data ?? [];
          if (Array.isArray(raw) && raw.length > 0) {
            const normalised = raw.map(t =>
              typeof t === "string" ? { name: t, count: null } : t
            );
            setTags(normalised);
            setTagsLoading(false);
            return; // done — dedicated endpoint worked
          }
        } catch {
          // No /tags endpoint — fall through to derive from questions
        }

        // Fallback: pull questions and count tags ourselves
        const res = await api.get("/questions");
        const questions = res.data?.questions ?? res.data ?? [];
        setTotalQuestions(questions.length);

        // Count occurrences of each tag across all questions
        const tagMap = {};
        questions.forEach(q => {
          const qtags = q.tags ?? [];
          qtags.forEach(t => {
            const name = typeof t === "string" ? t : t?.name;
            if (name) tagMap[name] = (tagMap[name] || 0) + 1;
          });
        });

        // Sort by usage count descending
        const derived = Object.entries(tagMap)
          .sort((a, b) => b[1] - a[1])
          .map(([name, count]) => ({ name, count }));

        setTags(derived);
      } catch {
        setTags([]);
      } finally {
        setTagsLoading(false);
      }
    };

    fetchTagsFromQuestions();
  }, []);

  // ── Fetch total question count separately if not already set ────────────
  useEffect(() => {
    if (totalQuestions !== null) return; // already set from above
    const fetchCount = async () => {
      try {
        const res = await api.get("/questions");
        const questions = res.data?.questions ?? res.data ?? [];
        const total = res.data?.total ?? res.data?.count ?? questions.length;
        setTotalQuestions(total);
      } catch {
        setTotalQuestions(null);
      }
    };
    fetchCount();
  }, [totalQuestions]);

  const handleTagClick = (tagName) => {
    setActiveTag(prev => prev === tagName ? null : tagName);
  };

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Orbitron:wght@400;600;900&family=Share+Tech+Mono&display=swap');
        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
        body { background: #020c14; overflow-x: hidden; }

        .home-root { min-height: 100vh; background: #020c14; font-family: 'Share Tech Mono', monospace; position: relative; overflow: hidden; }
        .home-root::before { content: ''; position: fixed; inset: 0; background-image: linear-gradient(rgba(0,255,200,0.025) 1px, transparent 1px), linear-gradient(90deg, rgba(0,255,200,0.025) 1px, transparent 1px); background-size: 52px 52px; pointer-events: none; z-index: 0; }
        .home-root::after { content: ''; position: fixed; inset: 0; background: radial-gradient(ellipse 60% 50% at 50% 0%, rgba(0,40,60,0.9) 0%, transparent 70%); pointer-events: none; z-index: 0; }

        .scanlines { position: fixed; inset: 0; z-index: 1; background: repeating-linear-gradient(0deg, transparent, transparent 2px, rgba(0,0,0,0.06) 2px, rgba(0,0,0,0.06) 4px); pointer-events: none; }
        .scan-beam { position: fixed; left: 0; right: 0; height: 2px; background: linear-gradient(90deg, transparent, rgba(0,255,200,0.12), rgba(0,255,200,0.4), rgba(0,200,255,0.3), transparent); z-index: 2; pointer-events: none; filter: blur(1px); }

        .statsbar { position: relative; z-index: 10; border-bottom: 1px solid rgba(0,255,200,0.08); background: rgba(2,12,20,0.85); backdrop-filter: blur(20px); padding: 0 32px; height: 44px; display: flex; align-items: center; justify-content: flex-end; gap: 24px; opacity: 0; transform: translateY(-6px); transition: opacity 0.6s ease, transform 0.6s ease; }
        .statsbar.on { opacity: 1; transform: translateY(0); }
        .stat { font-size: 10px; letter-spacing: 0.15em; color: rgba(0,255,200,0.35); text-transform: uppercase; }
        .stat strong { color: rgba(0,255,200,0.8); margin-right: 4px; }
        .stat-dot { width: 5px; height: 5px; border-radius: 50%; background: #00ffc8; box-shadow: 0 0 6px #00ffc8; animation: blink 1.8s ease-in-out infinite; }
        @keyframes blink { 0%,100%{opacity:1;} 50%{opacity:0.2;} }

        .layout { position: relative; z-index: 5; display: flex; max-width: 1200px; margin: 0 auto; padding: 32px 24px; gap: 28px; opacity: 0; transform: translateY(20px); transition: opacity 0.7s 0.2s ease, transform 0.7s 0.2s ease; }
        .layout.on { opacity: 1; transform: translateY(0); }

        /* Sidebar */
        .sidebar { width: 210px; flex-shrink: 0; }
        .sidebar-hdr { display: flex; align-items: center; gap: 8px; margin-bottom: 14px; }
        .sidebar-title { font-family: 'Orbitron', sans-serif; font-size: 11px; font-weight: 600; letter-spacing: 0.28em; text-transform: uppercase; color: rgba(0,255,200,0.65); }
        .sidebar-line { flex: 1; height: 1px; background: linear-gradient(90deg, rgba(0,255,200,0.25), transparent); }

        .tag-skel { height: 34px; margin-bottom: 4px; background: linear-gradient(90deg, rgba(0,255,200,0.04) 25%, rgba(0,255,200,0.07) 50%, rgba(0,255,200,0.04) 75%); background-size: 200% 100%; animation: skel 1.4s ease-in-out infinite; border: 1px solid rgba(0,255,200,0.05); }
        @keyframes skel { 0%{background-position:200% 0;} 100%{background-position:-200% 0;} }

        .tag-empty { font-size: 10px; color: rgba(0,255,200,0.2); letter-spacing: 0.15em; text-transform: uppercase; padding: 10px 0; }

        .tag-item { display: flex; align-items: center; justify-content: space-between; padding: 8px 12px; margin-bottom: 4px; border: 1px solid rgba(0,255,200,0.07); background: rgba(0,255,200,0.02); cursor: pointer; position: relative; overflow: hidden; transition: border-color 0.2s, background 0.2s, transform 0.15s; }
        .tag-item::before { content: ''; position: absolute; left: 0; top: 0; bottom: 0; width: 0; background: rgba(0,255,200,0.05); transition: width 0.25s ease; }
        .tag-item:hover::before, .tag-item.active::before { width: 100%; }
        .tag-item:hover, .tag-item.active { border-color: rgba(0,255,200,0.35); transform: translateX(3px); }
        .tag-item.active { border-color: rgba(0,255,200,0.5); }
        .tag-left { display: flex; align-items: center; gap: 7px; font-size: 12px; color: rgba(0,255,200,0.65); letter-spacing: 0.04em; position: relative; }
        .tag-item.active .tag-left { color: #00ffc8; }
        .tag-arrow { font-size: 8px; color: rgba(0,255,200,0.25); transition: color 0.2s; }
        .tag-item:hover .tag-arrow, .tag-item.active .tag-arrow { color: #00ffc8; }
        .tag-count { font-size: 10px; color: rgba(0,200,255,0.4); letter-spacing: 0.04em; }

        /* Main */
        .main { flex: 1; min-width: 0; }
        .main-hdr { display: flex; align-items: flex-start; justify-content: space-between; margin-bottom: 24px; flex-wrap: wrap; gap: 12px; }
        .main-eyebrow { font-size: 9px; letter-spacing: 0.3em; text-transform: uppercase; color: rgba(0,255,200,0.38); margin-bottom: 5px; }
        .main-title { font-family: 'Orbitron', sans-serif; font-size: 22px; font-weight: 900; color: #e6fff8; letter-spacing: 0.08em; text-transform: uppercase; }
        .main-title span { color: #00ffc8; }

        .search-indicator { display: inline-flex; align-items: center; gap: 8px; margin-top: 6px; padding: 3px 10px 3px 12px; border: 1px solid rgba(0,255,200,0.25); background: rgba(0,255,200,0.04); font-size: 11px; color: rgba(0,255,200,0.7); letter-spacing: 0.06em; }
        .search-indicator button { background: none; border: none; color: rgba(0,255,200,0.4); cursor: pointer; font-size: 14px; padding: 0; transition: color 0.2s; }
        .search-indicator button:hover { color: #00ffc8; }

        .ask-btn { display: flex; align-items: center; gap: 8px; padding: 10px 20px; background: transparent; border: 1px solid rgba(0,255,200,0.4); color: #00ffc8; font-family: 'Orbitron', sans-serif; font-size: 10px; font-weight: 700; letter-spacing: 0.25em; text-transform: uppercase; cursor: pointer; position: relative; overflow: hidden; transition: border-color 0.25s, box-shadow 0.25s, color 0.25s; }
        .ask-btn::before { content: ''; position: absolute; inset: 0; background: linear-gradient(135deg, rgba(0,255,200,0.1), rgba(0,150,255,0.06)); opacity: 0; transition: opacity 0.25s; }
        .ask-btn:hover::before { opacity: 1; }
        .ask-btn:hover { border-color: #00ffc8; box-shadow: 0 0 24px rgba(0,255,200,0.14); color: #fff; }

        .filter-bar { display: flex; align-items: center; gap: 6px; margin-bottom: 18px; padding-bottom: 14px; border-bottom: 1px solid rgba(0,255,200,0.06); flex-wrap: wrap; }
        .filter-btn { padding: 5px 13px; font-family: 'Share Tech Mono', monospace; font-size: 10px; letter-spacing: 0.15em; text-transform: uppercase; background: transparent; border: 1px solid rgba(0,255,200,0.1); color: rgba(0,255,200,0.38); cursor: pointer; transition: border-color 0.2s, color 0.2s, background 0.2s; }
        .filter-btn:hover { border-color: rgba(0,255,200,0.3); color: rgba(0,255,200,0.7); }
        .filter-btn.active { border-color: rgba(0,255,200,0.5); color: #00ffc8; background: rgba(0,255,200,0.05); }
        .filter-sep { flex: 1; }
        .result-count { font-size: 10px; letter-spacing: 0.1em; color: rgba(0,255,200,0.28); }

        .tag-pill { display: inline-flex; align-items: center; gap: 8px; padding: 4px 10px 4px 12px; border: 1px solid rgba(0,255,200,0.28); background: rgba(0,255,200,0.05); font-size: 11px; color: rgba(0,255,200,0.75); letter-spacing: 0.08em; margin-bottom: 14px; }
        .tag-pill button { background: none; border: none; color: rgba(0,255,200,0.4); cursor: pointer; font-size: 15px; line-height: 1; padding: 0; transition: color 0.2s; }
        .tag-pill button:hover { color: #00ffc8; }

        .panel { position: relative; border: 1px solid rgba(0,255,200,0.1); padding: 24px; background: rgba(2,12,20,0.5); backdrop-filter: blur(12px); }
        .pb { position: absolute; width: 16px; height: 16px; }
        .pb-tl { top:-1px; left:-1px;   border-top:1px solid rgba(0,255,200,0.5); border-left:1px solid rgba(0,255,200,0.5); }
        .pb-tr { top:-1px; right:-1px;  border-top:1px solid rgba(0,255,200,0.5); border-right:1px solid rgba(0,255,200,0.5); }
        .pb-bl { bottom:-1px; left:-1px;  border-bottom:1px solid rgba(0,255,200,0.5); border-left:1px solid rgba(0,255,200,0.5); }
        .pb-br { bottom:-1px; right:-1px; border-bottom:1px solid rgba(0,255,200,0.5); border-right:1px solid rgba(0,255,200,0.5); }
      `}</style>

      <div className="home-root">
        <div className="scanlines" />
        <div className="scan-beam" style={{ top: `${scanY}%` }} />

        <div className={`statsbar ${mounted ? "on" : ""}`}>
          {totalQuestions !== null && (
            <div className="stat"><strong>{totalQuestions.toLocaleString()}</strong> questions</div>
          )}
          {tags.length > 0 && (
            <div className="stat"><strong>{tags.length}</strong> tags</div>
          )}
          <div className="stat-dot" />
        </div>

        <div className={`layout ${mounted ? "on" : ""}`}>

          {/* Sidebar — tags derived from real question data */}
          <aside className="sidebar">
            <div className="sidebar-hdr">
              <span className="sidebar-title">Tags</span>
              <div className="sidebar-line" />
            </div>

            {tagsLoading ? (
              [...Array(5)].map((_, i) => (
                <div key={i} className="tag-skel" style={{ width: `${68 + (i * 8) % 32}%` }} />
              ))
            ) : tags.length === 0 ? (
              <div className="tag-empty">// No tags yet</div>
            ) : (
              tags.map(tag => (
                <div
                  key={tag.name}
                  className={`tag-item ${activeTag === tag.name ? "active" : ""}`}
                  onClick={() => handleTagClick(tag.name)}
                >
                  <div className="tag-left">
                    <span className="tag-arrow">▶</span>
                    {tag.name}
                  </div>
                  {tag.count !== null && (
                    <span className="tag-count">{tag.count}</span>
                  )}
                </div>
              ))
            )}
          </aside>

          <main className="main">
            <div className="main-hdr">
              <div>
                <div className="main-eyebrow">// Browse knowledge base</div>
                <h1 className="main-title">All <span>Questions</span></h1>
                {searchQuery && (
                  <div className="search-indicator">
                    <span>search: {searchQuery}</span>
                    <button onClick={() => navigate("/")}>×</button>
                  </div>
                )}
              </div>
              <button className="ask-btn" onClick={() => navigate("/ask")}>
                <span style={{ fontSize: 16, lineHeight: 1 }}>+</span>
                Ask Question
              </button>
            </div>

            <div className="filter-bar">
              {["Latest", "Active", "Unanswered", "Hot"].map(f => (
                <button
                  key={f}
                  className={`filter-btn ${activeFilter === f ? "active" : ""}`}
                  onClick={() => setActiveFilter(f)}
                >
                  {f}
                </button>
              ))}
              <div className="filter-sep" />
              <span className="result-count">
                {activeTag
                  ? `tag: ${activeTag}`
                  : searchQuery
                  ? `results for "${searchQuery}"`
                  : totalQuestions !== null
                  ? `${totalQuestions.toLocaleString()} questions`
                  : ""}
              </span>
            </div>

            {activeTag && (
              <div className="tag-pill">
                <span>tag: {activeTag}</span>
                <button onClick={() => setActiveTag(null)}>×</button>
              </div>
            )}

            <div className="panel">
              <div className="pb pb-tl" /><div className="pb pb-tr" />
              <div className="pb pb-bl" /><div className="pb pb-br" />
              <QuestionList
                activeTag={activeTag}
                filter={activeFilter}
                search={searchQuery}
              />
            </div>
          </main>
        </div>
      </div>
    </>
  );
}
